// Grab the incoming binary attachments array
const binaryData = $input.last().binary;
const outputItems = [];

// Loop through all binary elements looking for keys starting with 'resumes'
for (const [key, fileData] of Object.entries(binaryData)) {
  if (key.startsWith('resumes')) {
    outputItems.push({
      json: {
        // Keep the already extracted JD text attached to every single resume object instance
        jd_text: $node["Extract_JD"].json.text 
      },
      binary: {
        // Break this specific resume out as its own separate execution item
        resume_file: fileData 
      }
    });
  }
}

return outputItems;

// Loop through all items incoming from the AI Agent
return $input.all().map(item => {
  const data = item.json.output;

  return {
    json: {
      candidate_name: data.candidate_name || "Unknown",
      match_percentage: data.match_percentage || 0,
      matching_skills: Array.isArray(data.matching_skills) ? data.matching_skills.join(', ') : (data.matching_skills || ""),
      non_matching_skills: Array.isArray(data.non_matching_skills) ? data.non_matching_skills.join(', ') : (data.non_matching_skills || ""),
      final_recommendation: data.final_recommendation || ""
    }
  };
});
